function Particles({ dark }) {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    const ctx = canvas.getContext("2d");
    let id;
    let W = (canvas.width = window.innerWidth);
    let H = (canvas.height = window.innerHeight);
    const dots = Array.from({ length: 60 }, () => ({ x: Math.random()*W, y: Math.random()*H, r: Math.random()*1.2+0.35, vx: (Math.random()-0.5)*0.16, vy: (Math.random()-0.5)*0.16, a: Math.random()*0.4+0.1 }));
    const onResize = () => { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; };
    window.addEventListener("resize", onResize);
    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      for (const d of dots) {
        d.x += d.vx; d.y += d.vy;
        if (d.x<0) d.x=W; if (d.x>W) d.x=0; if (d.y<0) d.y=H; if (d.y>H) d.y=0;
        ctx.beginPath(); ctx.arc(d.x, d.y, d.r, 0, Math.PI*2);
        ctx.fillStyle = dark ? `rgba(0,245,160,${d.a*0.7})` : `rgba(80,80,200,${d.a*0.32})`;
        ctx.fill();
      }
      for (let i=0; i<dots.length; i++) for (let j=i+1; j<dots.length; j++) {
        const dx=dots[i].x-dots[j].x, dy=dots[i].y-dots[j].y, dist=Math.sqrt(dx*dx+dy*dy);
        if (dist<95) { ctx.beginPath(); ctx.moveTo(dots[i].x,dots[i].y); ctx.lineTo(dots[j].x,dots[j].y); ctx.strokeStyle = dark ? `rgba(0,245,160,${0.05*(1-dist/95)})` : `rgba(80,80,200,${0.032*(1-dist/95)})`; ctx.lineWidth=0.4; ctx.stroke(); }
      }
      id = requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(id); window.removeEventListener("resize", onResize); };
  }, [dark]);
  return <canvas ref={ref} style={{ position:"fixed", top:0, left:0, width:"100%", height:"100%", zIndex:0, pointerEvents:"none", opacity:0.35 }} />;
}

function Typewriter({ strings }) {
  const [disp, setDisp] = useState("");
  const [si, setSi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);
  useEffect(() => {
    const cur = strings[si]; let t;
    if (!del && ci < cur.length) t = setTimeout(() => setCi(c=>c+1), 65);
    else if (!del && ci===cur.length) t = setTimeout(() => setDel(true), 2000);
    else if (del && ci>0) t = setTimeout(() => setCi(c=>c-1), 38);
    else { setDel(false); setSi(s=>(s+1)%strings.length); }
    setDisp(cur.slice(0,ci));
    return () => clearTimeout(t);
  }, [ci, del, si, strings]);
  return <span>{disp}<span style={{ borderRight:"2px solid #00f5a0", marginLeft:2, animation:"blink 1s step-end infinite" }} /></span>;
}

function SkillBar({ name, level, cat, dark, delay }) {
  const [w, setW] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setTimeout(() => setW(level), delay); }, { threshold:0.4 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [level, delay]);
  return (
    <div ref={ref} style={{ marginBottom:32, animation:"fadeUp 0.6s ease both" }}>
      <div style={{ display:"flex", justifyContent:"space-between", marginBottom:10, gap:12 }}>
        <span style={{ fontSize:"clamp(13px,1.5vw,15px)", fontFamily:"Space Mono,monospace", color:dark?"#e0e0e0":"#222", fontWeight:500 }}>{name}</span>
        <span style={{ fontSize:"clamp(11px,1.3vw,12px)", color:dark?"#00f5a0":"#5050c8", fontFamily:"monospace", whiteSpace:"nowrap" }}>{cat} · {level}%</span>
      </div>
      <div style={{ height:6, borderRadius:3, background:dark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.09)", overflow:"hidden", boxShadow:`inset 0 1px 2px ${dark?"rgba(0,0,0,0.3)":"rgba(0,0,0,0.05)"}` }}>
        <div style={{ height:"100%", width:`${w}%`, borderRadius:3, background:dark?"linear-gradient(90deg,#00f5a0,#00b4d8)":"linear-gradient(90deg,#5050c8,#a78bfa)", transition:"width 1.4s cubic-bezier(0.34,1.56,0.64,1)", boxShadow:dark?`0 0 20px rgba(0,245,160,0.4)`:`0 0 12px rgba(80,80,200,0.3)` }} />
      </div>
    </div>
  );
}

